        @JavascriptInterface
        fun saveToLocalStorage(key: String, value: String): Boolean {
            if (!isCallerOriginValid()) return false
            if (!isValidStorageKey(key) || !isValidStorageValue(value)) return false
            
            return try {
                val prefs = context.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
                prefs.edit().putString(sanitizeKey(key), value).apply()
                true
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun getFromLocalStorage(key: String): String? {
            if (!isCallerOriginValid()) return null
            if (!isValidStorageKey(key)) return null
            
            return try {
                val prefs = context.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
                prefs.getString(sanitizeKey(key), null)
            } catch (e: Exception) {
                null
            }
        }

