        fun removeFromLocalStorage(key: String): Boolean {
            if (!isCallerOriginValid()) return false
            if (!isValidStorageKey(key)) return false
            
            return try {
                val prefs = context.getSharedPreferences("WebAppStorage", Context.MODE_PRIVATE)
                prefs.edit().remove(sanitizeKey(key)).apply()
                true
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun requestPushNotificationToken() {
