                    }

                    val token = task.result
                    val sanitizedToken = sanitizeForJavaScript(token ?: "")
                    webView.evaluateJavascript("window.onPushTokenResult('$sanitizedToken');", null)
                })
            }
        }

        @JavascriptInterface
