                    if (intent.resolveActivity(packageManager) != null) {
                        startActivity(intent)
                    }
                } catch (e: Exception) {
                    Toast.makeText(context, "Cannot open camera", Toast.LENGTH_SHORT).show()
                }
            }
            return true
        }

        @JavascriptInterface
