        private fun isValidStorageKey(key: String): Boolean {
            return key.length in 1..256 && key.matches(Regex("^[a-zA-Z0-9_.-]+$"))
        }

        private fun isValidStorageValue(value: String): Boolean {
            return value.length <= 1048576
        }

        private fun sanitizeKey(key: String): String {
            return key.replace(Regex("[^a-zA-Z0-9_.-]"), "")
        }

        private fun sanitizeForJavaScript(input: String): String {
            return input.replace("\\", "\\\\")
                .replace("'", "\\'")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
        }

        private fun sanitizeForJson(input: String): String {
